import{_ as e,o as i,c as l,a0 as t}from"./chunks/framework.CED9SG98.js";const u=JSON.parse('{"title":"PKMS (Personal Knowledge Management System)","description":"个人知识管理系统，基于 OKF 存储格式 + llmwiki 增量编译机制构建的知识库","frontmatter":{"type":"Concept","title":"PKMS (Personal Knowledge Management System)","description":"个人知识管理系统，基于 OKF 存储格式 + llmwiki 增量编译机制构建的知识库","source_url":"n/a","source_title":"n/a","source_platform":"内部","ingest_date":"2026-07-11T00:00:00.000Z","access_date":"2026-07-11T00:00:00.000Z","tags":["知识管理","PKMS","OKF","llmwiki","方法论"],"status":"compiled","review_count":0,"last_review":"2026-07-11T00:00:00.000Z","next_review":"2026-07-12T00:00:00.000Z"},"headers":[],"relativePath":"wiki/concepts/PKMS.md","filePath":"wiki/concepts/PKMS.md"}'),n={name:"wiki/concepts/PKMS.md"};function s(o,a,r,h,c,d){return i(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="pkms-personal-knowledge-management-system" tabindex="-1">PKMS (Personal Knowledge Management System) <a class="header-anchor" href="#pkms-personal-knowledge-management-system" aria-label="Permalink to &quot;PKMS (Personal Knowledge Management System)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>PKMS 是<strong>个人知识管理系统</strong>，将知识从「收藏」升级为「编译」——不是保存原文，而是让 AI 理解、提炼、关联、维护，形成可复利增长的知识资产。</p><h2 id="三层架构" tabindex="-1">三层架构 <a class="header-anchor" href="#三层架构" aria-label="Permalink to &quot;三层架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Raw Sources（原始材料）      ← 用户丢进来的文章、笔记（只读，不可变）</span></span>
<span class="line"><span>      ↓</span></span>
<span class="line"><span>The Wiki（知识层）            ← LLM 理解、提炼、关联、维护（LLM 全权负责）</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>The Schema（模式层）          ← AGENTS.md 定义规则</span></span></code></pre></div><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><h3 id="_1-ingest-入库" tabindex="-1">1. Ingest（入库） <a class="header-anchor" href="#_1-ingest-入库" aria-label="Permalink to &quot;1. Ingest（入库）&quot;">​</a></h3><ul><li>用户发送链接 + &quot;加入知识库&quot;</li><li>LLM 读取内容 → 确认理解 → 写入 Raw → 编译 Wiki → 关联追问</li></ul><h3 id="_2-query-查询" tabindex="-1">2. Query（查询） <a class="header-anchor" href="#_2-query-查询" aria-label="Permalink to &quot;2. Query（查询）&quot;">​</a></h3><ul><li>基于已编译知识回答，而非 RAG 检索</li><li>回答本身可存为新 wiki 页面</li></ul><h3 id="_3-review-复习" tabindex="-1">3. Review（复习） <a class="header-anchor" href="#_3-review-复习" aria-label="Permalink to &quot;3. Review（复习）&quot;">​</a></h3><ul><li>间隔重复：1天 → 3天 → 7天 → 14天 → 30天</li><li>LLM 主动提问，用户回忆</li></ul><h3 id="_4-lint-健康检查" tabindex="-1">4. Lint（健康检查） <a class="header-anchor" href="#_4-lint-健康检查" aria-label="Permalink to &quot;4. Lint（健康检查）&quot;">​</a></h3><ul><li>每周扫描：孤儿页、矛盾、过时、缺失链接</li></ul><h2 id="与-okf-的关系" tabindex="-1">与 OKF 的关系 <a class="header-anchor" href="#与-okf-的关系" aria-label="Permalink to &quot;与 OKF 的关系&quot;">​</a></h2><ul><li>OKF 提供<strong>存储格式</strong>（markdown + YAML frontmatter）</li><li>PKMS 提供<strong>工作流</strong>（Ingest → Query → Review → Lint）</li></ul><h2 id="与-llmwiki-的关系" tabindex="-1">与 llmwiki 的关系 <a class="header-anchor" href="#与-llmwiki-的关系" aria-label="Permalink to &quot;与 llmwiki 的关系&quot;">​</a></h2><ul><li>llmwiki 提供<strong>增量编译</strong>理念</li><li>PKMS 实现为具体的工作协议和目录结构</li></ul><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><ul><li><a href="/eason-pkms/concepts/OKF.html">OKF</a> — 存储格式规范</li><li><a href="/eason-pkms/concepts/llmwiki.html">llmwiki</a> — 增量编译模式</li><li><a href="/eason-pkms/concepts/DIKW.html">DIKW</a> — 知识内化金字塔，PKMS 设计的底层框架</li><li><a href="/eason-pkms/entities/Eason.html">Eason</a> — 使用者</li><li><a href="/eason-pkms/sources/2026-07-12-karpathy-zhishiku-huiche.html">Andrew《90%的 Karpathy 同款知识库注定要吃灰》</a> — PKMS 设计的重要参考，AI 辅助 vs 人工思考的边界</li></ul><h1 id="citations" tabindex="-1">Citations <a class="header-anchor" href="#citations" aria-label="Permalink to &quot;Citations&quot;">​</a></h1><ul><li>来源: AGENTS.md 规则定义</li><li>灵感: Karpathy llmwiki + Google OKF</li></ul>`,22)])])}const p=e(n,[["render",s]]);export{u as __pageData,p as default};
